// Get transcript segments from WayinVideo response
const segments = $('4. WayinVideo — Get Transcript Results').item.json.data.transcript || [];

if (segments.length === 0) {
  throw new Error('Transcript is empty — check if the video URL is valid and publicly accessible.');
}

// Format transcript with speaker labels and timestamps for GPT
const formattedTranscript = segments
  .map(s => {
    const timeInSeconds = Math.floor(s.start / 1000);
    const minutes = Math.floor(timeInSeconds / 60);
    const seconds = timeInSeconds % 60;
    const timestamp = `${minutes}:${seconds.toString().padStart(2, '0')}`;
    return `[${s.speaker} | ${timestamp}] ${s.text.trim()}`;
  })
  .join('\n');

// Calculate duration
const lastSegment = segments[segments.length - 1];
const totalDurationMs = lastSegment?.end || 0;
const totalMinutes = Math.round(totalDurationMs / 60000);

// Unique speakers
const speakers = [...new Set(segments.map(s => s.speaker))];

// Word count
const wordCount = segments.map(s => s.text).join(' ').split(/\s+/).length;

return [{
  json: {
    formattedTranscript,
    wordCount,
    totalMinutes,
    speakerCount: speakers.length,
    speakers: speakers.join(', '),
    webinarTitle: $('1. Form — Webinar URL + Details').item.json['Webinar Title'],
    speakerName: $('1. Form — Webinar URL + Details').item.json['Speaker / Presenter Name'],
    topicCategory: $('1. Form — Webinar URL + Details').item.json['Topic Category'],
    webinarDate: $('1. Form — Webinar URL + Details').item.json['Webinar Date'],
    targetTeam: $('1. Form — Webinar URL + Details').item.json['Target Team / Department'] || 'All Teams',
    videoUrl: $('1. Form — Webinar URL + Details').item.json['Webinar / Recording URL']
  }
}];

// Parse AI output — extract JSON array of topics
const output = $input.first().json.output || '';

let topics = [];
try {
  // Strip any markdown formatting if present
  const cleaned = output
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  // Find JSON array in output
  const match = cleaned.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (match) {
    topics = JSON.parse(match[0]);
  } else {
    topics = JSON.parse(cleaned);
  }
} catch (e) {
  throw new Error('Could not parse AI output as JSON. Check the AI prompt output: ' + output.substring(0, 200));
}

if (!Array.isArray(topics) || topics.length === 0) {
  throw new Error('No topics extracted from AI output.');
}

// Add webinar metadata to each topic
const webinarTitle = $('7. Code — Format Transcript').item.json.webinarTitle;
const speakerName = $('7. Code — Format Transcript').item.json.speakerName;
const topicCategory = $('7. Code — Format Transcript').item.json.topicCategory;
const webinarDate = $('7. Code — Format Transcript').item.json.webinarDate;
const targetTeam = $('7. Code — Format Transcript').item.json.targetTeam;
const videoUrl = $('7. Code — Format Transcript').item.json.videoUrl;
const totalMinutes = $('7. Code — Format Transcript').item.json.totalMinutes;

return topics.map((topic, index) => ({
  json: {
    // Topic data
    topicTitle: topic.topic_title || `Topic ${index + 1}`,
    topicSummary: topic.topic_summary || '',
    keyInsights: Array.isArray(topic.key_insights) ? topic.key_insights : [],
    actionItems: Array.isArray(topic.action_items) ? topic.action_items : [],
    notableQuotes: Array.isArray(topic.notable_quotes) ? topic.notable_quotes : [],
    timestamps: topic.timestamps || '',
    tags: Array.isArray(topic.tags) ? topic.tags : [],

    // Webinar metadata
    webinarTitle,
    speakerName,
    topicCategory,
    webinarDate,
    targetTeam,
    videoUrl,
    totalMinutes,
    topicIndex: index + 1,

    // Build Notion page content in Markdown
    notionPageContent: [
      `## Summary`,
      topic.topic_summary || '',
      ``,
      `## Key Insights`,
      ...(topic.key_insights || []).map(insight => `- ${insight}`),
      ``,
      `## Action Items`,
      ...(topic.action_items || []).map(action => `- [ ] ${action}`),
      ``,
      ...(topic.notable_quotes && topic.notable_quotes.length > 0 ? [
        `## Notable Quotes`,
        ...topic.notable_quotes.map(quote => `> "${quote}"`),
        ``
      ] : []),
      `## Webinar Details`,
      `- **Webinar:** ${webinarTitle}`,
      `- **Speaker:** ${speakerName}`,
      `- **Date:** ${webinarDate}`,
      `- **Duration:** ${totalMinutes} minutes`,
      `- **Timestamps in recording:** ${topic.timestamps || 'N/A'}`,
      `- **Target Team:** ${targetTeam}`,
      `- **Recording URL:** ${videoUrl}`
    ].join('\n')
  }
}));
